3.solution:
def is_anagram(s1, s2):
    char_count = {}
    for ch in s1:
        char_count[ch] = char_count.get(ch, 0) + 1
    for ch in s2:
        if ch not in char_count or char_count[ch] == 0:
            return False
        char_count[ch] -= 1
    return all(count == 0 for count in char_count.values())

